// frontend/src/App.js
import { useNodesState, useEdgesState } from "reactflow";
import { PipelineToolbar } from "./toolbar";
import { PipelineUI } from "./ui";
import FlowCanvas from "./FlowCanvas";

function App() {
  const [nodes, setNodes, onNodesChange] = useNodesState([]);
  const [edges, setEdges, onEdgesChange] = useEdgesState([]);

  // ✅ Define handler first
  const handleDeleteNode = (targetId) => {
    setNodes((nds) => nds.filter((n) => n.id !== targetId));
    setEdges((eds) => eds.filter((e) => e.source !== targetId && e.target !== targetId));
  };

  // ✅ Now initialNodes can safely reference it
  const initialNodes = [
    { id: "1", type: "inputNode", position: { x: 50, y: 50 }, data: {} },
    { id: "2", type: "llmNode", position: { x: 300, y: 50 }, data: {} },
    { id: "3", type: "textNode", position: { x: 50, y: 200 }, data: {} },
    { id: "4", type: "outputNode", position: { x: 300, y: 200 }, data: {} },
    {
      id: "5",
      type: "deleteNode",
      position: { x: 200, y: 300 },
      data: { targetId: "2", onDelete: handleDeleteNode }, // ✅ bound correctly
    },
  ];

  const initialEdges = [
    { id: "e1-2", source: "1", target: "2" },
    { id: "e3-2", source: "3", target: "2" },
    { id: "e2-4", source: "2", target: "4" },
  ];

  // ✅ Initialize state with initialNodes/edges
  const [nodesState, setNodesState, onNodesChangeState] = useNodesState(initialNodes);
  const [edgesState, setEdgesState, onEdgesChangeState] = useEdgesState(initialEdges);

  return (
    <div>
      <PipelineToolbar />
      <PipelineUI />
      <FlowCanvas
        nodes={nodesState}
        edges={edgesState}
        onNodesChange={onNodesChangeState}
        onEdgesChange={onEdgesChangeState}
        onConnect={(params) => setEdgesState((eds) => [...eds, params])}
      />
    </div>
  );
}

export default App;
